/**
 * AdminSidebar — собственный сайдбар админки (Figma 6442:341438 «sidemenu2»).
 * Рейка воркспейсов 1–7 + «Admin» (активна) + панель с пунктами «Реферальная» /
 * «Модули» + футер профиля. Открывается по «Admin» в рейке любого кабинета.
 *
 * Reuse DS: MenuRail · MenuBadge · MenuPanel · MenuNavItem · MenuFooter.
 */

const WORKSPACES: { label: string; color: MenuBadgeColor }[] = [
  { label: "1", color: "red" },
  { label: "2", color: "orange" },
  { label: "3", color: "yellow" },
  { label: "4", color: "green" },
  { label: "5", color: "blue" },
  { label: "6", color: "blue-strong" },
  { label: "7", color: "purple" },
  { label: "8", color: "cyan" },
];

