export function AdminSidebar({ current = "referral" }: { current?: "referral" | "modules" }) {
  const router = useRouter();

  return (
    <div className="sticky top-0 z-30 hidden h-screen shrink-0 lg:flex">
      <MenuRail
        height="100vh"
        brand={
          <MenuBadge brand aria-label="О компании" onClick={() => router.push("/cabinet/about")}>
            <MenuIcon.Brand />
          </MenuBadge>
        }
        footer={
          <MenuFooter
            role="button"
            tabIndex={0}
            className="cursor-pointer bg-[var(--color-grey-90)]"
            onClick={() => router.push(CABINET_ROUTES.subdivision)}
            onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); router.push(CABINET_ROUTES.subdivision); } }}
          >
            Admin
          </MenuFooter>
        }
      >
        {WORKSPACES.map((w) => {
          const href = railHref(w.label);
          return (
            <MenuBadge key={w.label} color={w.color} onClick={href ? () => router.push(href) : undefined}>
              {w.label}
            </MenuBadge>
          );
        })}
      </MenuRail>

      <MenuPanel
        height="100vh"
        footer={
          <MenuFooter
            avatar={LK_USER.avatar}
            avatarRing
            role="button"
            tabIndex={0}
            className="cursor-pointer"
            onClick={() => router.push("/cabinet/lk/chair")}
            onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); router.push("/cabinet/lk/chair"); } }}
          >
            Пред. правления
          </MenuFooter>
        }
      >
        <MenuNavItem
          icon={<ReferralIcon className="ds-lm-nav__icon" />}
          active={current === "referral"}
          className="mt-[17px]"
          onClick={() => router.push("/cabinet/admin")}
        >
          Реферальная
        </MenuNavItem>
        <MenuNavItem
          icon={<ModulesIcon className="ds-lm-nav__icon" />}
          active={current === "modules"}
          onClick={() => router.push("/cabinet/admin/modules")}
        >
          Модули
        </MenuNavItem>
      </MenuPanel>
    </div>
  );
}
